import{c as t,Q as o,j as a,m as s}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Checkout — troubleshooting","description":"Symptom → fix for the most common hosted-checkout issues.","frontmatter":{"title":"Checkout — troubleshooting","description":"Symptom → fix for the most common hosted-checkout issues."},"headers":[],"relativePath":"checkout/troubleshooting.md","filePath":"checkout/troubleshooting.md","lastUpdated":1778983454000}'),i={name:"checkout/troubleshooting.md"};function n(r,e,u,l,h,d){return o(),a("div",null,[...e[0]||(e[0]=[s('<div class="warning custom-block"><p class="custom-block-title">🚧 In development — not in the Testing Guide</p><p>This surface is still being hardened and isn&#39;t part of the judge/user <a href="/guide/">Testing Guide</a>. The page below describes the intended design. To evaluate MuHaven today, use <a href="/havenbot/overview">HavenBot</a> or the <a href="/mcp/overview">MCP server</a>.</p></div><h1 id="hosted-checkout-troubleshooting" tabindex="-1">Hosted Checkout troubleshooting <a class="header-anchor" href="#hosted-checkout-troubleshooting" aria-label="Permalink to &quot;Hosted Checkout troubleshooting&quot;">​</a></h1><h2 id="issuer-side" tabindex="-1">Issuer side <a class="header-anchor" href="#issuer-side" aria-label="Permalink to &quot;Issuer side&quot;">​</a></h2><h3 id="havenbot-won-t-show-me-the-create-checkout-tool" tabindex="-1">&quot;HavenBot won&#39;t show me the create-checkout tool&quot; <a class="header-anchor" href="#havenbot-won-t-show-me-the-create-checkout-tool" aria-label="Permalink to &quot;&quot;HavenBot won&#39;t show me the create-checkout tool&quot;&quot;">​</a></h3><p>Three checks:</p><ol><li><strong>You&#39;re signed in as an issuer.</strong> Investor passkeys don&#39;t see this tool.</li><li><strong>Your issuer status is <code>approved</code>.</strong> Pending / suspended → 403 NOT_APPROVED_ISSUER.</li><li><strong>You&#39;re on the right network.</strong> Some testnet deploys don&#39;t have the checkout backend wired; check <code>/health</code> on <code>api.muhaven.app</code>.</li></ol><h3 id="created-the-link-shared-it-buyer-says-session-not-found" tabindex="-1">&quot;Created the link, shared it, buyer says &#39;Session not found&#39;&quot; <a class="header-anchor" href="#created-the-link-shared-it-buyer-says-session-not-found" aria-label="Permalink to &quot;&quot;Created the link, shared it, buyer says &#39;Session not found&#39;&quot;&quot;">​</a></h3><p>The fragment got stripped in transit. Common channels that strip fragments:</p><ul><li>Some markdown renderers (Slack message link auto-cards on certain workspace settings).</li><li>URL shorteners (bit.ly, t.co, etc.).</li><li>Click-track wrappers (HubSpot, Marketo, etc.).</li><li>Corporate email gateways with link-rewriting (Microsoft Safe Links, Mimecast).</li></ul><p>Re-share as <strong>plain text</strong> (preserves the <code>#k=...</code> part) over a non-rewriting channel (Signal, plain SMS, direct DM).</p><h3 id="webhook-isn-t-firing" tabindex="-1">&quot;Webhook isn&#39;t firing&quot; <a class="header-anchor" href="#webhook-isn-t-firing" aria-label="Permalink to &quot;&quot;Webhook isn&#39;t firing&quot;&quot;">​</a></h3><p>In order:</p><ol><li><strong>Verify the URL is reachable</strong> from MuHaven&#39;s egress IP. <code>curl -I</code> from your laptop isn&#39;t enough — your endpoint may have IP-allowlist gates that don&#39;t include MuHaven&#39;s IPs.</li><li><strong>Check that the URL passed the SSRF guard.</strong> If <code>create_checkout</code> returned <code>400 INVALID_WEBHOOK_URL</code>, your URL is on the deny-list (RFC1918 / loopback / link-local). Use a public HTTPS URL.</li><li><strong>Check your endpoint isn&#39;t returning 5xx.</strong> MuHaven retries 5 times with backoff, then marks the webhook as <code>failed</code>. The audit log entry tells you which delivery attempt failed.</li><li><strong>Check <code>MuHaven-Signature</code> verification on your side.</strong> If you&#39;re returning 4xx because the signature check fails, MuHaven treats it as success-from-you and stops retrying. Make sure you verify on the <strong>raw body bytes</strong>, not the JSON-parsed string.</li></ol><h3 id="webhook-fired-but-with-stale-data" tabindex="-1">&quot;Webhook fired but with stale data&quot; <a class="header-anchor" href="#webhook-fired-but-with-stale-data" aria-label="Permalink to &quot;&quot;Webhook fired but with stale data&quot;&quot;">​</a></h3><p>The retry mechanism uses the <strong>same</strong> event payload — if you got an out-of-order delivery (T+30s retry arrives before T+0s original due to network jitter), the <code>Idempotency-Key</code> lets you dedupe.</p><h3 id="i-want-to-cancel-a-session-but-it-says-already-paid" tabindex="-1">&quot;I want to cancel a session but it says <code>already paid</code>&quot; <a class="header-anchor" href="#i-want-to-cancel-a-session-but-it-says-already-paid" aria-label="Permalink to &quot;&quot;I want to cancel a session but it says `already paid`&quot;&quot;">​</a></h3><p>Sessions become immutable once they hit a terminal state (<code>paid</code> / <code>expired</code> / <code>cancelled</code>). You can&#39;t un-cancel or re-mint a paid session — mint a new checkout if you need to invoice again.</p><h3 id="the-webhook-payload-is-missing-fields-i-expected" tabindex="-1">&quot;The webhook payload is missing fields I expected&quot; <a class="header-anchor" href="#the-webhook-payload-is-missing-fields-i-expected" aria-label="Permalink to &quot;&quot;The webhook payload is missing fields I expected&quot;&quot;">​</a></h3><p>Webhook payloads are intentionally minimal. If you need additional fields (e.g., buyer&#39;s encrypted balance handle), the design choice was: webhook = bare facts; full enrichment via the dashboard / HavenBot. File an issue if you need a specific field.</p><h2 id="buyer-side" tabindex="-1">Buyer side <a class="header-anchor" href="#buyer-side" aria-label="Permalink to &quot;Buyer side&quot;">​</a></h2><h3 id="i-clicked-the-link-but-the-page-is-blank-shows-session-not-found" tabindex="-1">&quot;I clicked the link but the page is blank / shows &#39;Session not found&#39;&quot; <a class="header-anchor" href="#i-clicked-the-link-but-the-page-is-blank-shows-session-not-found" aria-label="Permalink to &quot;&quot;I clicked the link but the page is blank / shows &#39;Session not found&#39;&quot;&quot;">​</a></h3><p>Three possibilities:</p><ol><li><strong>The URL fragment was stripped.</strong> Ask the issuer to re-share — the <code>#k=...</code> part must be present.</li><li><strong>The session expired.</strong> Check the URL for an obviously old timestamp; ask for a fresh one.</li><li><strong>The session was cancelled.</strong> Ask the issuer to re-mint.</li></ol><h3 id="passkey-creation-dialog-doesn-t-appear" tabindex="-1">&quot;Passkey creation dialog doesn&#39;t appear&quot; <a class="header-anchor" href="#passkey-creation-dialog-doesn-t-appear" aria-label="Permalink to &quot;&quot;Passkey creation dialog doesn&#39;t appear&quot;&quot;">​</a></h3><ul><li>Confirm your browser supports WebAuthn (Chrome / Edge / Safari / Firefox, current versions).</li><li>On macOS: enable iCloud Keychain (System Settings → Passwords).</li><li>On Windows: enable Windows Hello (Settings → Accounts → Sign-in options).</li><li>Some incognito / private modes disable WebAuthn — open in a normal window.</li></ul><h3 id="created-passkey-but-checkout-says-insufficient-mhusdc" tabindex="-1">&quot;Created passkey, but checkout says &#39;Insufficient mhUSDC&#39;&quot; <a class="header-anchor" href="#created-passkey-but-checkout-says-insufficient-mhusdc" aria-label="Permalink to &quot;&quot;Created passkey, but checkout says &#39;Insufficient mhUSDC&#39;&quot;&quot;">​</a></h3><p>You need mhUSDC to complete the purchase.</p><ul><li><strong>On testnet:</strong> click the <strong>Faucet</strong> button; receive 100 mhUSDC; come back.</li><li><strong>On production:</strong> use the on-ramp picker shown at checkout (pay with card / Apple Pay / Google Pay).</li></ul><h3 id="funding-succeeded-but-checkout-still-says-waiting-for-funds" tabindex="-1">&quot;Funding succeeded but checkout still says &#39;Waiting for funds&#39;&quot; <a class="header-anchor" href="#funding-succeeded-but-checkout-still-says-waiting-for-funds" aria-label="Permalink to &quot;&quot;Funding succeeded but checkout still says &#39;Waiting for funds&#39;&quot;&quot;">​</a></h3><p>The polling interval is 5 seconds; balance updates register shortly after funds land. If it persists:</p><ol><li>Verify the funds landed in your <strong>MuHaven wallet address</strong> (not your EOA). The checkout shows your MuHaven wallet address; the faucet may have funded a different address by accident.</li><li>Refresh the page; on reload, the buy ceremony re-checks balance.</li></ol><h3 id="confirm-button-signed-but-the-page-is-stuck-on-settling" tabindex="-1">&quot;Confirm button signed but the page is stuck on &#39;Settling…&#39;&quot; <a class="header-anchor" href="#confirm-button-signed-but-the-page-is-stuck-on-settling" aria-label="Permalink to &quot;&quot;Confirm button signed but the page is stuck on &#39;Settling…&#39;&quot;&quot;">​</a></h3><p>The settlement waits for an on-chain event. Three checks:</p><ol><li><strong>Tx submitted?</strong> Open Arbiscan with your MuHaven wallet address; if the buy UserOp is there, settlement is on-chain.</li><li><strong>SSE channel disconnected?</strong> Refresh. The page re-subscribes.</li><li><strong>Indexer lag?</strong> The indexer can have occasional lag spikes. Wait. If still stuck, the buy still settled — open the dashboard at <code>muhaven.app/portfolio</code> to see the encrypted balance.</li></ol><h3 id="got-settled-but-the-issuer-says-they-didn-t-receive-a-webhook" tabindex="-1">&quot;Got &#39;Settled&#39; but the issuer says they didn&#39;t receive a webhook&quot; <a class="header-anchor" href="#got-settled-but-the-issuer-says-they-didn-t-receive-a-webhook" aria-label="Permalink to &quot;&quot;Got &#39;Settled&#39; but the issuer says they didn&#39;t receive a webhook&quot;&quot;">​</a></h3><p>The webhook may have failed (the issuer&#39;s endpoint was down). The buy settled on-chain regardless; the issuer can verify via:</p><ul><li>Their HavenBot&#39;s SSE notification.</li><li>The dashboard <code>checkout_sessions</code> row showing <code>status: paid</code>.</li><li>The on-chain <code>Subscription.Purchase</code> event with your MuHaven wallet + the session ID in metadata.</li></ul><p>This is a &quot;webhook delivery is best-effort&quot; property — on-chain settlement is the source of truth.</p><h2 id="multi-buyer" tabindex="-1">Multi-buyer <a class="header-anchor" href="#multi-buyer" aria-label="Permalink to &quot;Multi-buyer&quot;">​</a></h2><h3 id="can-two-buyers-redeem-the-same-link" tabindex="-1">&quot;Can two buyers redeem the same link?&quot; <a class="header-anchor" href="#can-two-buyers-redeem-the-same-link" aria-label="Permalink to &quot;&quot;Can two buyers redeem the same link?&quot;&quot;">​</a></h3><p>No — sessions are single-use. The first successful settlement marks <code>status: paid</code> and subsequent attempts return <code>409 ALREADY_PAID</code>.</p><p>If you need a multi-buyer link, mint a separate session per buyer.</p><h3 id="i-m-a-returning-buyer-using-my-existing-muhaven-wallet-—-why-does-the-page-ask-me-to-create-a-passkey" tabindex="-1">&quot;I&#39;m a returning buyer using my existing MuHaven wallet — why does the page ask me to create a passkey?&quot; <a class="header-anchor" href="#i-m-a-returning-buyer-using-my-existing-muhaven-wallet-—-why-does-the-page-ask-me-to-create-a-passkey" aria-label="Permalink to &quot;&quot;I&#39;m a returning buyer using my existing MuHaven wallet — why does the page ask me to create a passkey?&quot;&quot;">​</a></h3><p>Two possibilities:</p><ol><li><strong>You&#39;re on a different device</strong> without your synced passkey. Your iCloud Keychain / Google Password Manager hasn&#39;t synced this device yet; let it catch up and refresh.</li><li><strong>You created your MuHaven wallet on a different domain.</strong> If you originally signed up on <code>*.hasto.dev</code> (pre-2026-05-11 migration), your passkey doesn&#39;t migrate to <code>muhaven.app</code>. Create a new one; the new MuHaven wallet will have its own audit log starting from this purchase.</li></ol><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/checkout/for-issuers">For issuers</a> — full create-link walkthrough.</li><li><a href="/checkout/for-buyers">For buyers</a> — the buyer-side flow.</li><li><a href="/checkout/webhooks">Webhooks &amp; receipts</a> — verifier code and retry semantics.</li><li><a href="/checkout/fragment-key">URL fragment key</a> — the privacy mechanic.</li></ul>',47)])])}const b=t(i,[["render",n]]);export{p as __pageData,b as default};
